import axios from 'axios';
import {BASE_PATH_APIS} from '../../utils/constants';

class ReverseConnectorService {

    async fetchReverseConnectorConfig() {
        try {
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/get/reverse_connector_config');
            return response;
        } catch (error) {

        }
        return null;
    }

    async fetchReverseConnectorMasterList() {
        try {
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/get_connector_reverse_master');
            return response;
        } catch (error) {

            return [];
        }
    }

    async saveReverseConnectorConfig(config) {
        try {
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/addOrUpdate/reverse_connector_config', config);
            return response;
        } catch (error) {

        }
        return null;
    }

}

export const reverseConnectorService = new ReverseConnectorService();
